import numpy as np

def damped_pinv(J, lam=0.05):
    """Damped least-squares pseudoinverse - well-behaved near singularities."""
    I = np.eye(J.shape[0])
    return J.T @ np.linalg.inv(J @ J.T + lam * lam * I)

