import numpy as np

# Slow: per-pixel python loop (~10 sec for 1280×720)
def threshold_slow(img, lo, hi):
    out = np.zeros_like(img)
    for y in range(img.shape[0]):
        for x in range(img.shape[1]):
            if lo <= img[y, x] <= hi: out[y, x] = 255
    return out

# Fast: numpy mask (~1 ms for 1280×720). Same result.
def threshold_fast(img, lo, hi):
    return np.where((img >= lo) & (img <= hi), 255, 0).astype(np.uint8)

#include <rclcpp/rclcpp.hpp>
#include <geometry_msgs/msg/twist.hpp>
#include <sensor_msgs/msg/laser_scan.hpp>

class MyNode : public rclcpp::Node {
public:
  MyNode() : Node("my_node") {
    sub_ = create_subscription<sensor_msgs::msg::LaserScan>(
        "/scan", 10,
        [this](sensor_msgs::msg::LaserScan::SharedPtr msg) { on_scan(msg); });
    pub_ = create_publisher<geometry_msgs::msg::Twist>("/cmd_vel", 10);
    timer_ = create_wall_timer(
        std::chrono::milliseconds(100),
        [this]() { tick(); });
  }

private:
  void on_scan(sensor_msgs::msg::LaserScan::SharedPtr msg) {
    min_range_ = *std::min_element(msg->ranges.begin(), msg->ranges.end());
  }
  void tick() {
    geometry_msgs::msg::Twist cmd;
    cmd.linear.x = (min_range_ > 0.5) ? 0.2 : 0.0;
    pub_->publish(cmd);
  }

  rclcpp::Subscription<sensor_msgs::msg::LaserScan>::SharedPtr sub_;
  rclcpp::Publisher<geometry_msgs::msg::Twist>::SharedPtr     pub_;
  rclcpp::TimerBase::SharedPtr                                 timer_;
  float min_range_{std::numeric_limits<float>::infinity()};
};

int main(int argc, char** argv) {
  rclcpp::init(argc, argv);
  rclcpp::spin(std::make_shared<MyNode>());
  rclcpp::shutdown();
  return 0;
}

