class KF1D:
    def __init__(self, x0, p0, q, r):
        self.x, self.P, self.Q, self.R = x0, p0, q, r

    def predict(self):
        self.P += self.Q

    def update(self, z):
        K       = self.P / (self.P + self.R)
        self.x  = self.x + K * (z - self.x)
        self.P  = (1 - K) * self.P

kf = KF1D(x0=0, p0=1, q=0.01, r=0.1)
